1	package com.booking.controller;
2	
3	import com.booking.domain.User;
4	import com.booking.service.AuthService;
5	import com.booking.util.SessionUtil;
6	import jakarta.servlet.http.HttpSession;
7	import org.springframework.http.ResponseEntity;
8	import org.springframework.web.bind.annotation.*;
9	
10	import java.util.Map;
11	
12	@RestController
13	@RequestMapping("/api/auth")
14	public class AuthController {
15	
16	    private final AuthService authService;
17	
18	    public AuthController(AuthService authService) {
19	        this.authService = authService;
20	    }
21	
22	    @PostMapping("/login")
23	    public ResponseEntity<?> login(@RequestBody Map<String, String> credentials,
24	                                   HttpSession session) {
25	        String username = credentials.get("username");
26	        String password = credentials.get("password");
27	
28	        if (username == null || password == null) {
29	            return ResponseEntity.badRequest().body(Map.of("error", "Username and password required"));
30	        }
31	
32	        User user = authService.authenticate(username, password);
33	        if (user == null) {
34	            return ResponseEntity.status(401).body(Map.of("error", "Invalid credentials"));
35	        }
36	
37	        SessionUtil.setCurrentUser(session, user);
38	        return ResponseEntity.ok(toUserResponse(user));
39	    }
40	
41	    @PostMapping("/register")
42	    public ResponseEntity<?> register(@RequestBody Map<String, String> data, HttpSession session) {
43	        // Strict DTO validation
44	        String username = data.get("username");
45	        String email = data.get("email");
46	        String password = data.get("password");
47	        String fullName = data.get("fullName");
48	
49	        if (username == null || username.isBlank()) {
50	            return ResponseEntity.badRequest().body(Map.of("error", "Username is required"));
51	        }
52	        if (email == null || !email.matches("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$")) {
53	            return ResponseEntity.badRequest().body(Map.of("error", "Valid email is required"));
54	        }
55	        if (password == null || password.length() < 6) {
56	            return ResponseEntity.badRequest().body(Map.of("error", "Password must be at least 6 characters"));
57	        }
58	        if (fullName == null || fullName.isBlank()) {
59	            return ResponseEntity.badRequest().body(Map.of("error", "Full name is required"));
60	        }
61	
62	        try {
63	            User user = authService.register(username, email, password, fullName,
64	                    data.get("phone"), 1L);
65	            SessionUtil.setCurrentUser(session, user);
66	            return ResponseEntity.ok(Map.of("message", "Registration successful", "userId", user.getId()));
67	        } catch (IllegalArgumentException e) {
68	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
69	        }
70	    }
71	
72	    @PostMapping("/logout")
73	    public ResponseEntity<?> logout(HttpSession session) {
74	        session.invalidate();
75	        return ResponseEntity.ok(Map.of("message", "Logged out"));
76	    }
77	
78	    @GetMapping("/me")
79	    public ResponseEntity<?> currentUser(HttpSession session) {
80	        User user = SessionUtil.getCurrentUser(session);
81	        if (user == null) {
82	            return ResponseEntity.status(401).body(Map.of("error", "Not authenticated"));
83	        }
84	        return ResponseEntity.ok(toUserResponse(user));
85	    }
86	
87	    private Map<String, Object> toUserResponse(User user) {
88	        return Map.of(
89	                "id", user.getId(),
90	                "username", user.getUsername(),
91	                "email", user.getEmail(),
92	                "fullName", user.getFullName(),
93	                "role", user.getRoleName()
94	        );
95	    }
96	}
