17	@RestController
18	@RequestMapping("/api/orders")
19	public class OrderController {
20	
21	    private final OrderService orderService;
22	    private final IdempotencyService idempotencyService;
23	    private final ObjectMapper objectMapper;
24	
25	    public OrderController(OrderService orderService,
26	                           IdempotencyService idempotencyService,
27	                           ObjectMapper objectMapper) {
28	        this.orderService = orderService;
29	        this.idempotencyService = idempotencyService;
30	        this.objectMapper = objectMapper;
31	    }
32	
33	    @GetMapping
34	    public ResponseEntity<?> list(HttpSession session) {
35	        User user = SessionUtil.getCurrentUser(session);
