58	
59	    @PostMapping
60	    public ResponseEntity<?> create(@RequestBody Map<String, Object> body,
61	                                    @RequestHeader(value = "Idempotency-Key") String idempotencyKey,
62	                                    HttpSession session) {
63	        String action = "CREATE_ORDER";
64	        IdempotencyResult idem = idempotencyService.checkToken(idempotencyKey, action, null);
65	        if (idem.isDuplicate) {
66	            return ResponseEntity.status(idem.cachedStatus).body(idem.cachedBody);
67	        }
68	
69	        User user = SessionUtil.getCurrentUser(session);
70	        try {
71	            Long listingId = ((Number) body.get("listingId")).longValue();
72	            Long timeSlotId = ((Number) body.get("timeSlotId")).longValue();
73	            Long addressId = body.get("addressId") != null ? ((Number) body.get("addressId")).longValue() : null;
74	            String notes = (String) body.get("notes");
75	            String deliveryMode = (String) body.get("deliveryMode");
76	
77	            Order order = orderService.createOrder(listingId, timeSlotId, addressId, notes, deliveryMode, user);
78	
79	            String responseBody = objectMapper.writeValueAsString(order);
80	            // For CREATE, orderId was null at check time — use null for consistent scoped key
81	            idempotencyService.recordResponse(idempotencyKey, action, null, 200, responseBody);
82	            return ResponseEntity.ok(order);
83	        } catch (IllegalArgumentException | IllegalStateException e) {
84	            idempotencyService.recordResponse(idempotencyKey, action, null, 400, e.getMessage());
85	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
86	        } catch (SecurityException e) {
87	            idempotencyService.recordResponse(idempotencyKey, action, null, 403, e.getMessage());
88	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
89	        } catch (Exception e) {
90	            idempotencyService.recordResponse(idempotencyKey, action, null, 500, e.getMessage());
91	            return ResponseEntity.internalServerError().body(Map.of("error", "Order creation failed"));
92	        }
93	    }
94	
95	    @PostMapping("/{id}/confirm")
96	    public ResponseEntity<?> confirm(@PathVariable Long id,
97	                                     @RequestHeader(value = "Idempotency-Key") String key,
98	                                     HttpSession session) {
99	        return executeAction(key, "CONFIRM", id, session, (order, user) -> orderService.confirm(id, user));
100	    }
101	
102	    @PostMapping("/{id}/pay")
103	    public ResponseEntity<?> pay(@PathVariable Long id, @RequestBody Map<String, Object> body,
104	                                 @RequestHeader(value = "Idempotency-Key") String key,
105	                                 HttpSession session) {
106	        return executeAction(key, "PAY", id, session, (order, user) -> {
107	            BigDecimal amount = new BigDecimal(body.get("amount").toString());
108	            String ref = (String) body.get("paymentReference");
109	            return orderService.recordPayment(id, amount, ref, user);
110	        });
111	    }
112	
113	    @PostMapping("/{id}/check-in")
114	    public ResponseEntity<?> checkIn(@PathVariable Long id,
115	                                     @RequestHeader(value = "Idempotency-Key") String key,
116	                                     HttpSession session) {
117	        return executeAction(key, "CHECK_IN", id, session, (order, user) -> orderService.checkIn(id, user));
118	    }
119	
120	    @PostMapping("/{id}/check-out")
121	    public ResponseEntity<?> checkOut(@PathVariable Long id,
122	                                      @RequestHeader(value = "Idempotency-Key") String key,
123	                                      HttpSession session) {
124	        return executeAction(key, "CHECK_OUT", id, session, (order, user) -> orderService.checkOut(id, user));
125	    }
126	
127	    @PostMapping("/{id}/complete")
128	    public ResponseEntity<?> complete(@PathVariable Long id,
129	                                      @RequestHeader(value = "Idempotency-Key") String key,
130	                                      HttpSession session) {
131	        return executeAction(key, "COMPLETE", id, session, (order, user) -> orderService.complete(id, user));
132	    }
133	
134	    @PostMapping("/{id}/cancel")
135	    public ResponseEntity<?> cancel(@PathVariable Long id, @RequestBody Map<String, String> body,
136	                                    @RequestHeader(value = "Idempotency-Key") String key,
137	                                    HttpSession session) {
138	        return executeAction(key, "CANCEL", id, session,
139	                (order, user) -> orderService.cancel(id, body.get("reason"), user));
140	    }
141	
142	    @PostMapping("/{id}/refund")
143	    public ResponseEntity<?> refund(@PathVariable Long id, @RequestBody Map<String, Object> body,
144	                                    @RequestHeader(value = "Idempotency-Key") String key,
145	                                    HttpSession session) {
146	        return executeAction(key, "REFUND", id, session, (order, user) -> {
147	            BigDecimal amount = new BigDecimal(body.get("amount").toString());
148	            String reason = (String) body.get("reason");
149	            return orderService.refund(id, amount, reason, user);
150	        });
151	    }
152	
153	    @PostMapping("/{id}/reschedule")
154	    public ResponseEntity<?> reschedule(@PathVariable Long id, @RequestBody Map<String, Object> body,
155	                                        @RequestHeader(value = "Idempotency-Key") String key,
156	                                        HttpSession session) {
157	        return executeAction(key, "RESCHEDULE", id, session, (order, user) -> {
158	            Long newSlotId = ((Number) body.get("newTimeSlotId")).longValue();
159	            return orderService.reschedule(id, newSlotId, user);
160	        });
161	    }
162	
163	    @FunctionalInterface
164	    private interface OrderAction {
165	        Order execute(Order order, User user);
166	    }
167	
168	    private ResponseEntity<?> executeAction(String idempotencyKey, String action,
169	                                            Long orderId, HttpSession session,
170	                                            OrderAction orderAction) {
171	        IdempotencyResult idem = idempotencyService.checkToken(idempotencyKey, action, orderId);
172	        if (idem.isDuplicate) {
173	            return ResponseEntity.status(idem.cachedStatus).body(idem.cachedBody);
174	        }
175	
176	        User user = SessionUtil.getCurrentUser(session);
177	        try {
178	            Order order = orderService.getById(orderId);
179	            if (order == null) {
180	                idempotencyService.recordResponse(idempotencyKey, action, null, 404, "Order not found");
181	                return ResponseEntity.notFound().build();
182	            }
183	            if (!orderService.canUserAccess(order, user)) {
184	                idempotencyService.recordResponse(idempotencyKey, action, orderId, 403, "Access denied");
185	                return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
186	            }
187	
188	            Order result = orderAction.execute(order, user);
189	            String body = objectMapper.writeValueAsString(result);
190	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 200, body);
191	            return ResponseEntity.ok(result);
192	        } catch (IllegalArgumentException | IllegalStateException e) {
193	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 400, e.getMessage());
194	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
195	        } catch (SecurityException e) {
196	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 403, e.getMessage());
197	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
198	        } catch (Exception e) {
199	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 500, e.getMessage());
200	            return ResponseEntity.internalServerError().body(Map.of("error", "Operation failed"));
201	        }
202	    }
203	}
