72	    // ---- Manual Adjustment with mandatory note + audit ----
73	    @PostMapping("/adjust")
74	    public ResponseEntity<?> adjust(@RequestBody Map<String, Object> body, HttpSession session) {
75	        User admin = RoleGuard.requireAdmin(session);
76	        Long userId = ((Number) body.get("userId")).longValue();
77	        int pts = ((Number) body.get("points")).intValue();
78	        String reason = (String) body.get("reason");
79	
80	        if (reason == null || reason.isBlank()) {
81	            return ResponseEntity.badRequest().body(Map.of("error", "Reason is mandatory for adjustments"));
82	        }
83	
84	        int balanceBefore = pointsService.getBalance(userId);
85	
86	        if (pts > 0) {
87	            pointsService.awardPoints(userId, pts, "ADMIN_ADJUST", "ADMIN", admin.getId(), reason);
88	        } else {
89	            pointsService.deductPoints(userId, Math.abs(pts), "ADMIN_ADJUST", "ADMIN", admin.getId(), reason);
90	        }
91	
92	        int balanceAfter = pointsService.getBalance(userId);
93	
94	        // Immutable audit record
95	        PointsAdjustment adj = new PointsAdjustment();
96	        adj.setUserId(userId);
97	        adj.setAdjustedBy(admin.getId());
98	        adj.setPoints(pts);
99	        adj.setReason(reason);
100	        adj.setBalanceBefore(balanceBefore);
101	        adj.setBalanceAfter(balanceAfter);
102	        adjustmentMapper.insert(adj);
103	
104	        return ResponseEntity.ok(Map.of("balanceBefore", balanceBefore, "balanceAfter", balanceAfter,
105	                "adjustment", pts, "reason", reason));
106	    }
