128	            String description = (String) body.get("description");
129	            return ResponseEntity.ok(pointsService.awardPoints(userId, pts,
130	                    "ADMIN_AWARD", "ADMIN", admin.getId(), description));
131	        } catch (Exception e) {
132	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
133	        }
134	    }
135	}
