35	    /**
36	     * Checks an idempotency token scoped to a specific order+action combination.
37	     * The compound key prevents caching collisions across different actions on the same order.
38	     */
39	    public IdempotencyResult checkToken(String token, String action, Long orderId) {
40	        if (token == null || token.isBlank()) return new IdempotencyResult(false, null, null);
41	
42	        // Build a compound key: token + action + orderId to prevent cross-action collisions
43	        String scopedKey = token + "::" + action + "::" + (orderId != null ? orderId : "new");
44	
45	        IdempotencyToken existing = tokenMapper.findByToken(scopedKey);
46	        if (existing != null) {
47	            if (existing.isExpired()) {
48	                return new IdempotencyResult(false, null, null);
49	            }
50	            if (existing.getResponseStatus() != null) {
51	                return new IdempotencyResult(true, existing.getResponseStatus(), existing.getResponseBody());
52	            }
53	            return new IdempotencyResult(true, 409, "{\"error\":\"Request is already being processed\"}");
54	        }
55	
56	        IdempotencyToken newToken = new IdempotencyToken();
57	        newToken.setToken(scopedKey);
58	        newToken.setAction(action);
59	        newToken.setOrderId(orderId);
60	        newToken.setExpiresAt(LocalDateTime.now().plusMinutes(TOKEN_VALIDITY_MINUTES));
61	        try {
62	            tokenMapper.insert(newToken);
63	        } catch (Exception e) {
64	            return new IdempotencyResult(true, 409, "{\"error\":\"Duplicate request\"}");
65	        }
66	
67	        return new IdempotencyResult(false, null, null);
68	    }
