41	    /**
42	     * Award points to a user by trigger event, respecting the configured rule scope.
43	     * INDIVIDUAL: awards to the specific user.
44	     * DEPARTMENT/TEAM: awards to all users sharing the same department/team.
45	     */
46	    @Transactional
47	    public void awardByTrigger(String triggerEvent, Long userId, String refType, Long refId, String context) {
48	        PointsRule rule = ruleMapper.findByTrigger(triggerEvent);
49	        if (rule == null || !rule.getActive()) return;
50	
51	        switch (rule.getScope()) {
52	            case "INDIVIDUAL" -> awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
53	                    rule.getDescription() + " " + context);
54	            case "DEPARTMENT" -> {
55	                User user = userMapper.findById(userId);
56	                if (user != null && user.getDepartment() != null) {
57	                    List<User> deptUsers = userMapper.findByDepartment(user.getDepartment());
58	                    for (User u : deptUsers) {
59	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
60	                                rule.getDescription() + " (dept: " + user.getDepartment() + ") " + context);
61	                    }
62	                } else {
63	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
64	                            rule.getDescription() + " " + context);
65	                }
66	            }
67	            case "TEAM" -> {
68	                User user = userMapper.findById(userId);
69	                if (user != null && user.getTeam() != null) {
70	                    List<User> teamUsers = userMapper.findByTeam(user.getTeam());
71	                    for (User u : teamUsers) {
72	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
73	                                rule.getDescription() + " (team: " + user.getTeam() + ") " + context);
74	                    }
75	                } else {
76	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
77	                            rule.getDescription() + " " + context);
78	                }
79	            }
80	            case "CLASS" -> {
81	                // CLASS scope: awards to all users sharing the same role
82	                User user = userMapper.findById(userId);
83	                if (user != null && user.getRoleId() != null) {
84	                    List<User> classUsers = userMapper.findByRoleId(user.getRoleId());
85	                    for (User u : classUsers) {
86	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
87	                                rule.getDescription() + " (class: " + user.getRoleName() + ") " + context);
88	                    }
89	                } else {
90	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
91	                            rule.getDescription() + " " + context);
92	                }
93	            }
94	            default -> awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
95	                    rule.getDescription() + " " + context);
96	        }
97	    }
