3	import com.booking.domain.User;
4	import com.booking.util.SessionUtil;
5	import jakarta.servlet.http.HttpSession;
6	import org.springframework.http.MediaType;
7	import org.springframework.web.bind.annotation.GetMapping;
8	import org.springframework.web.bind.annotation.RequestMapping;
9	import org.springframework.web.bind.annotation.RestController;
10	import org.springframework.web.servlet.mvc.method.annotation.SseEmitter;
11	
12	import java.io.IOException;
13	import java.util.List;
14	import java.util.Map;
15	import java.util.concurrent.ConcurrentHashMap;
16	import java.util.concurrent.CopyOnWriteArrayList;
17	
18	/**
19	 * Server-Sent Events endpoint for real-time chat push notifications.
20	 * Replaces the legacy 5-second polling approach.
21	 */
22	@RestController
23	@RequestMapping("/api/messages")
24	public class ChatSseController {
25	
26	    private final Map<Long, List<SseEmitter>> emitters = new ConcurrentHashMap<>();
27	
28	    @GetMapping(value = "/stream", produces = MediaType.TEXT_EVENT_STREAM_VALUE)
29	    public SseEmitter stream(HttpSession session) {
30	        User user = SessionUtil.getCurrentUser(session);
31	        SseEmitter emitter = new SseEmitter(300_000L); // 5-minute timeout
32	
33	        emitters.computeIfAbsent(user.getId(), k -> new CopyOnWriteArrayList<>()).add(emitter);
34	
35	        Runnable cleanup = () -> {
36	            List<SseEmitter> list = emitters.get(user.getId());
37	            if (list != null) {
38	                list.remove(emitter);
39	                if (list.isEmpty()) emitters.remove(user.getId());
40	            }
41	        };
42	        emitter.onCompletion(cleanup);
43	        emitter.onTimeout(cleanup);
44	        emitter.onError(e -> cleanup.run());
45	
46	        // Send initial keepalive so the client knows the stream is open
47	        try {
48	            emitter.send(SseEmitter.event().name("connected").data("ok"));
49	        } catch (IOException e) {
50	            emitter.complete();
51	        }
52	
53	        return emitter;
54	    }
55	
56	    /**
57	     * Push a new-message event to all active SSE connections for a given user.
58	     */
59	    public void pushMessageEvent(Long userId, Object payload) {
60	        List<SseEmitter> list = emitters.get(userId);
61	        if (list == null || list.isEmpty()) return;
62	        for (SseEmitter emitter : list) {
63	            try {
64	                emitter.send(SseEmitter.event().name("new-message").data(payload));
65	            } catch (IOException e) {
66	                emitter.complete();
67	            }
68	        }
69	    }
70	}
