5	import com.booking.domain.User;
6	import com.booking.mapper.ListingMapper;
7	import com.booking.mapper.TimeSlotMapper;
8	import org.springframework.stereotype.Service;
9	import org.springframework.transaction.annotation.Transactional;
10	
11	import java.time.LocalDate;
12	import java.util.List;
13	
14	@Service
15	public class TimeSlotService {
16	
17	    private final TimeSlotMapper timeSlotMapper;
18	    private final ListingMapper listingMapper;
19	
20	    public TimeSlotService(TimeSlotMapper timeSlotMapper, ListingMapper listingMapper) {
21	        this.timeSlotMapper = timeSlotMapper;
22	        this.listingMapper = listingMapper;
23	    }
24	
25	    public TimeSlot getById(Long id) {
26	        return timeSlotMapper.findById(id);
27	    }
28	
29	    public List<TimeSlot> getByListing(Long listingId) {
30	        return timeSlotMapper.findByListingId(listingId);
31	    }
32	
33	    public List<TimeSlot> getAvailable(Long listingId, LocalDate start, LocalDate end) {
34	        return timeSlotMapper.findAvailable(listingId, start, end);
35	    }
36	
37	    public TimeSlot create(TimeSlot slot, User actor) {
38	        Listing listing = listingMapper.findById(slot.getListingId());
39	        if (listing == null) throw new IllegalArgumentException("Listing not found");
40	        if (!"ADMINISTRATOR".equals(actor.getRoleName()) &&
41	            !listing.getPhotographerId().equals(actor.getId())) {
42	            throw new SecurityException("Only the listing owner can manage time slots");
43	        }
44	        if (slot.getCapacity() == null) slot.setCapacity(listing.getMaxConcurrent());
45	        if (slot.getBookedCount() == null) slot.setBookedCount(0);
46	        timeSlotMapper.insert(slot);
47	        return timeSlotMapper.findById(slot.getId());
48	    }
49	
50	    @Transactional
51	    public TimeSlot reserveSlot(Long slotId) {
52	        TimeSlot slot = timeSlotMapper.findByIdForUpdate(slotId);
53	        if (slot == null) throw new IllegalArgumentException("Time slot not found");
54	        if (!slot.hasAvailability()) {
55	            throw new IllegalStateException("Time slot is fully booked");
56	        }
57	        int updated = timeSlotMapper.incrementBookedCount(slotId, slot.getVersion());
58	        if (updated == 0) {
59	            throw new IllegalStateException("Concurrent booking conflict — please retry");
60	        }
61	        return timeSlotMapper.findById(slotId);
62	    }
63	
64	    @Transactional
65	    public void releaseSlot(Long slotId) {
66	        TimeSlot slot = timeSlotMapper.findByIdForUpdate(slotId);
67	        if (slot == null) return;
68	        timeSlotMapper.decrementBookedCount(slotId, slot.getVersion());
69	    }
70	}
