240	    @Transactional
241	    public Order refund(Long orderId, BigDecimal amount, String reason, User actor) {
242	        Order order = requireOrder(orderId);
243	        enforceAccess(order, actor, "ADMINISTRATOR");
244	
245	        OrderStatus current = OrderStatus.valueOf(order.getStatus());
246	        if (!current.isRefundable() && current != OrderStatus.CANCELLED) {
247	            throw new IllegalStateException("Order is not refundable in status " + current);
248	        }
249	
250	        if (current != OrderStatus.CANCELLED) {
251	            transition(order, OrderStatus.REFUNDED, actor.getId(),
252	                    "Refund of " + amount + ": " + reason);
253	        }
254	        // APPROVAL notification: inform customer of refund approval
255	        notificationService.queueApprovalNotification(order.getCustomerId(),
256	                order.getOrderNumber(), "Refund of $" + amount + " approved");
257	        order.setRefundAmount(amount);
258	        order.setStatus(order.getStatus().equals(OrderStatus.CANCELLED.name()) ?
259	                OrderStatus.CANCELLED.name() : OrderStatus.REFUNDED.name());
260	        orderMapper.update(order);
261	
262	        // Release slot if not already released
263	        if (current != OrderStatus.CANCELLED) {
264	            timeSlotService.releaseSlot(order.getTimeSlotId());
265	        }
266	
267	        // Deduct points — lookup the payment rule value for consistent reversal
268	        com.booking.domain.PointsRule payRule = pointsRuleMapper.findByTrigger("ORDER_PAID");
269	        int deductAmt = (payRule != null) ? payRule.getPoints() : 10;
270	        pointsService.deductPoints(order.getCustomerId(), deductAmt,
271	                "REFUND_DEDUCTION", "ORDER", order.getId(),
272	                "Points reversed for refunded order " + order.getOrderNumber());
273	
274	        notificationService.queueOrderNotification(order, "ORDER_REFUNDED",
275	                "Refund of $" + amount + " processed for order " + order.getOrderNumber());
276	        return orderMapper.findById(orderId);
277	    }
