33	public class MessageController {
34	
35	    private static final Set<String> ALLOWED_TYPES = Set.of("image/jpeg", "image/png");
36	    private static final long MAX_SIZE = 5 * 1024 * 1024; // 5MB
37	
38	    private final MessageService messageService;
39	    private final ChatAttachmentMapper chatAttachmentMapper;
40	    private final ConversationMapper conversationMapper;
41	    private final MessageMapper messageMapper;
42	    private final Path uploadDir;
43	
44	    public MessageController(MessageService messageService,
45	                             ChatAttachmentMapper chatAttachmentMapper,
46	                             ConversationMapper conversationMapper,
47	                             MessageMapper messageMapper,
48	                             @Value("${app.upload-dir}") String uploadDir) {
49	        this.messageService = messageService;
50	        this.chatAttachmentMapper = chatAttachmentMapper;
51	        this.conversationMapper = conversationMapper;
52	        this.messageMapper = messageMapper;
53	        this.uploadDir = Paths.get(uploadDir, "chat");
54	        try { Files.createDirectories(this.uploadDir); } catch (IOException ignored) {}
55	    }
56	
57	    @GetMapping("/conversations")
58	    public ResponseEntity<?> conversations(HttpSession session) {
59	        User user = SessionUtil.getCurrentUser(session);
60	        return ResponseEntity.ok(messageService.getConversations(user));
61	    }
62	
63	    @GetMapping("/conversations/{id}")
64	    public ResponseEntity<?> messages(@PathVariable Long id, HttpSession session) {
65	        User user = SessionUtil.getCurrentUser(session);
66	        try {
67	            List<Message> msgs = messageService.getMessages(id, user);
68	            // Attach chat attachment info to each message
69	            List<Map<String, Object>> result = new ArrayList<>();
70	            for (Message m : msgs) {
71	                Map<String, Object> entry = new LinkedHashMap<>();
72	                entry.put("id", m.getId());
73	                entry.put("conversationId", m.getConversationId());
74	                entry.put("senderId", m.getSenderId());
75	                entry.put("senderName", m.getSenderName());
76	                entry.put("content", m.getContent());
77	                entry.put("readAt", m.getReadAt());
78	                entry.put("createdAt", m.getCreatedAt());
79	                List<ChatAttachment> attachments = chatAttachmentMapper.findByMessageId(m.getId());
80	                entry.put("attachments", attachments);
81	                result.add(entry);
82	            }
83	            return ResponseEntity.ok(result);
84	        } catch (SecurityException e) {
85	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
86	        }
87	    }
88	
89	    @PostMapping("/send")
90	    public ResponseEntity<?> send(@RequestBody Map<String, Object> body, HttpSession session) {
91	        User user = SessionUtil.getCurrentUser(session);
92	        try {
93	            Long recipientId = ((Number) body.get("recipientId")).longValue();
94	            String content = (String) body.get("content");
95	            Long orderId = body.get("orderId") != null ? ((Number) body.get("orderId")).longValue() : null;
96	            Message msg = messageService.sendMessage(recipientId, content, orderId, user);
97	            return ResponseEntity.ok(msg);
98	        } catch (IllegalArgumentException e) {
99	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
100	        }
101	    }
102	
103	    @PostMapping("/conversations/{id}/reply")
104	    public ResponseEntity<?> reply(@PathVariable Long id, @RequestBody Map<String, String> body,
105	                                   HttpSession session) {
106	        User user = SessionUtil.getCurrentUser(session);
107	        try {
108	            Message msg = messageService.sendToConversation(id, body.get("content"), user);
109	            return ResponseEntity.ok(msg);
110	        } catch (SecurityException e) {
111	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
112	        } catch (IllegalArgumentException e) {
113	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
114	        }
115	    }
116	
117	    @PostMapping("/conversations/{id}/image")
118	    public ResponseEntity<?> uploadImage(@PathVariable Long id,
119	                                         @RequestParam("file") MultipartFile file,
120	                                         HttpSession session) {
121	        User user = SessionUtil.getCurrentUser(session);
122	
123	        Conversation conv = conversationMapper.findById(id);
124	        if (conv == null) return ResponseEntity.notFound().build();
125	        if (!conv.getParticipantOne().equals(user.getId()) &&
126	            !conv.getParticipantTwo().equals(user.getId()) &&
127	            !"ADMINISTRATOR".equals(user.getRoleName())) {
128	            return ResponseEntity.status(403).body(Map.of("error", "Not a participant"));
129	        }
130	
131	        if (!ALLOWED_TYPES.contains(file.getContentType())) {
132	            return ResponseEntity.badRequest().body(Map.of("error", "Only JPEG and PNG images are allowed"));
133	        }
134	        if (file.getSize() > MAX_SIZE) {
135	            return ResponseEntity.badRequest().body(Map.of("error", "File size must not exceed 5 MB"));
136	        }
137	
138	        // Create message with image indicator
139	        Message msg = messageService.sendToConversation(id, "[Image]", user);
140	
141	        String storedName = UUID.randomUUID() + "_" + file.getOriginalFilename()
142	                .replaceAll("[^a-zA-Z0-9._-]", "_");
143	        try {
144	            Files.copy(file.getInputStream(), uploadDir.resolve(storedName));
145	        } catch (IOException e) {
146	            return ResponseEntity.internalServerError().body(Map.of("error", "Failed to store image"));
147	        }
148	
149	        ChatAttachment att = new ChatAttachment();
150	        att.setMessageId(msg.getId());
151	        att.setFileName(storedName);
152	        att.setOriginalName(file.getOriginalFilename());
153	        att.setContentType(file.getContentType());
154	        att.setFileSize(file.getSize());
155	        chatAttachmentMapper.insert(att);
156	
157	        return ResponseEntity.ok(Map.of("message", msg, "attachment", att));
158	    }
159	
160	    @GetMapping("/attachments/{id}/download")
161	    public ResponseEntity<?> downloadImage(@PathVariable Long id, HttpSession session) {
162	        User user = SessionUtil.getCurrentUser(session);
163	        ChatAttachment att = chatAttachmentMapper.findById(id);
164	        if (att == null) return ResponseEntity.notFound().build();
165	
166	        // IDOR fix: verify caller is a participant of the conversation this attachment belongs to
167	        Message msg = messageMapper.findById(att.getMessageId());
168	        if (msg == null) return ResponseEntity.notFound().build();
169	        Conversation conv = conversationMapper.findById(msg.getConversationId());
170	        if (conv == null) return ResponseEntity.notFound().build();
171	        if (!conv.getParticipantOne().equals(user.getId()) &&
172	            !conv.getParticipantTwo().equals(user.getId()) &&
173	            !"ADMINISTRATOR".equals(user.getRoleName())) {
174	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
175	        }
176	
177	        try {
178	            Resource resource = new UrlResource(uploadDir.resolve(att.getFileName()).toUri());
179	            if (!resource.exists()) return ResponseEntity.notFound().build();
180	            return ResponseEntity.ok()
181	                    .contentType(MediaType.parseMediaType(att.getContentType()))
182	                    .header(HttpHeaders.CONTENT_DISPOSITION, "inline; filename=\"" + att.getOriginalName() + "\"")
183	                    .body(resource);
184	        } catch (MalformedURLException e) {
185	            return ResponseEntity.internalServerError().build();
186	        }
187	    }
188	}
