1	package com.booking.filter;
2	
3	import com.booking.domain.BlacklistEntry;
4	import com.booking.domain.User;
5	import com.booking.mapper.BlacklistMapper;
6	import com.booking.mapper.UserMapper;
7	import jakarta.servlet.Filter;
8	import jakarta.servlet.FilterChain;
9	import jakarta.servlet.ServletException;
10	import jakarta.servlet.ServletRequest;
11	import jakarta.servlet.ServletResponse;
12	import jakarta.servlet.http.HttpServletRequest;
13	import jakarta.servlet.http.HttpServletResponse;
14	import jakarta.servlet.http.HttpSession;
15	import org.springframework.stereotype.Component;
16	
17	import java.io.IOException;
18	
19	@Component
20	public class AuthFilter implements Filter {
21	
22	    private final BlacklistMapper blacklistMapper;
23	    private final UserMapper userMapper;
24	
25	    public AuthFilter(BlacklistMapper blacklistMapper, UserMapper userMapper) {
26	        this.blacklistMapper = blacklistMapper;
27	        this.userMapper = userMapper;
28	    }
29	
30	    @Override
31	    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
32	            throws IOException, ServletException {
33	
34	        HttpServletRequest httpReq = (HttpServletRequest) request;
35	        HttpServletResponse httpResp = (HttpServletResponse) response;
36	
37	        String path = httpReq.getRequestURI();
38	
39	        // Allow auth endpoints without session
40	        if (path.startsWith("/api/auth/")) {
41	            chain.doFilter(request, response);
42	            return;
43	        }
44	
45	        HttpSession session = httpReq.getSession(false);
46	        if (session == null || session.getAttribute("currentUser") == null) {
47	            httpResp.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
48	            httpResp.setContentType("application/json");
49	            httpResp.getWriter().write("{\"error\":\"Authentication required\"}");
50	            return;
51	        }
52	
53	        // Revalidate user enabled status from DB on every request
54	        User sessionUser = (User) session.getAttribute("currentUser");
55	        User freshUser = userMapper.findById(sessionUser.getId());
56	        if (freshUser == null || !Boolean.TRUE.equals(freshUser.getEnabled())) {
57	            session.invalidate();
58	            httpResp.setStatus(HttpServletResponse.SC_FORBIDDEN);
59	            httpResp.setContentType("application/json");
60	            httpResp.getWriter().write("{\"error\":\"Account is disabled\"}");
61	            return;
62	        }
63	
64	        // Check blacklist status
65	        BlacklistEntry bl = blacklistMapper.findActiveByUserId(sessionUser.getId());
66	        if (bl != null && !bl.isExpired()) {
67	            httpResp.setStatus(HttpServletResponse.SC_FORBIDDEN);
68	            httpResp.setContentType("application/json");
69	            httpResp.getWriter().write("{\"error\":\"Account is blacklisted: " +
70	                    bl.getReason().replace("\"", "'") + "\"}");
71	            return;
72	        }
73	
74	        chain.doFilter(request, response);
75	    }
76	}
