14	
15	@Service
16	public class PointsService {
17	
18	    private final PointsLedgerMapper ledgerMapper;
19	    private final PointsRuleMapper ruleMapper;
20	    private final UserMapper userMapper;
21	
22	    public PointsService(PointsLedgerMapper ledgerMapper, PointsRuleMapper ruleMapper,
23	                         UserMapper userMapper) {
24	        this.ledgerMapper = ledgerMapper;
25	        this.ruleMapper = ruleMapper;
26	        this.userMapper = userMapper;
27	    }
28	
29	    public int getBalance(Long userId) {
30	        return ledgerMapper.getBalance(userId);
31	    }
32	
33	    public List<PointsLedgerEntry> getHistory(Long userId) {
34	        return ledgerMapper.findByUserId(userId);
35	    }
36	
37	    public List<Map<String, Object>> getLeaderboard() {
38	        return ledgerMapper.getLeaderboard();
39	    }
40	
41	    /**
42	     * Award points to a user by trigger event, respecting the configured rule scope.
43	     * INDIVIDUAL: awards to the specific user.
44	     * DEPARTMENT/TEAM: awards to all users sharing the same department/team.
45	     */
46	    @Transactional
47	    public void awardByTrigger(String triggerEvent, Long userId, String refType, Long refId, String context) {
48	        PointsRule rule = ruleMapper.findByTrigger(triggerEvent);
49	        if (rule == null || !rule.getActive()) return;
50	
51	        switch (rule.getScope()) {
52	            case "INDIVIDUAL" -> awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
53	                    rule.getDescription() + " " + context);
54	            case "DEPARTMENT" -> {
55	                User user = userMapper.findById(userId);
56	                if (user != null && user.getDepartment() != null) {
57	                    List<User> deptUsers = userMapper.findByDepartment(user.getDepartment());
58	                    for (User u : deptUsers) {
59	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
60	                                rule.getDescription() + " (dept: " + user.getDepartment() + ") " + context);
61	                    }
62	                } else {
63	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
64	                            rule.getDescription() + " " + context);
65	                }
66	            }
67	            case "TEAM" -> {
68	                User user = userMapper.findById(userId);
69	                if (user != null && user.getTeam() != null) {
70	                    List<User> teamUsers = userMapper.findByTeam(user.getTeam());
71	                    for (User u : teamUsers) {
72	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
73	                                rule.getDescription() + " (team: " + user.getTeam() + ") " + context);
74	                    }
75	                } else {
76	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
77	                            rule.getDescription() + " " + context);
78	                }
79	            }
80	            case "CLASS" -> {
81	                // CLASS scope: awards to all users sharing the same role
82	                User user = userMapper.findById(userId);
83	                if (user != null && user.getRoleId() != null) {
84	                    List<User> classUsers = userMapper.findByRoleId(user.getRoleId());
85	                    for (User u : classUsers) {
86	                        awardPoints(u.getId(), rule.getPoints(), rule.getName(), refType, refId,
87	                                rule.getDescription() + " (class: " + user.getRoleName() + ") " + context);
88	                    }
89	                } else {
90	                    awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
91	                            rule.getDescription() + " " + context);
92	                }
93	            }
94	            default -> awardPoints(userId, rule.getPoints(), rule.getName(), refType, refId,
95	                    rule.getDescription() + " " + context);
96	        }
97	    }
98	
99	    @Transactional
100	    public PointsLedgerEntry awardPoints(Long userId, int points, String action,
101	                                         String refType, Long refId, String description) {
102	        int currentBalance = ledgerMapper.getBalance(userId);
103	        int newBalance = currentBalance + points;
104	
105	        PointsLedgerEntry entry = new PointsLedgerEntry();
106	        entry.setUserId(userId);
107	        entry.setPoints(points);
108	        entry.setBalanceAfter(newBalance);
109	        entry.setAction(action);
110	        entry.setReferenceType(refType);
111	        entry.setReferenceId(refId);
112	        entry.setDescription(description);
113	        ledgerMapper.insert(entry);
114	        ledgerMapper.updateUserBalance(userId, newBalance);
115	
116	        return entry;
117	    }
118	
119	    @Transactional
120	    public PointsLedgerEntry deductPoints(Long userId, int points, String action,
121	                                          String refType, Long refId, String description) {
122	        int currentBalance = ledgerMapper.getBalance(userId);
123	        int newBalance = Math.max(0, currentBalance - points);
124	
125	        PointsLedgerEntry entry = new PointsLedgerEntry();
126	        entry.setUserId(userId);
127	        entry.setPoints(-points);
128	        entry.setBalanceAfter(newBalance);
129	        entry.setAction(action);
130	        entry.setReferenceType(refType);
131	        entry.setReferenceId(refId);
132	        entry.setDescription(description);
133	        ledgerMapper.insert(entry);
134	        ledgerMapper.updateUserBalance(userId, newBalance);
135	
136	        return entry;
137	    }
138	}
