1	package com.booking.service;
2	
3	import com.booking.domain.IdempotencyToken;
4	import com.booking.mapper.IdempotencyTokenMapper;
5	import com.fasterxml.jackson.databind.ObjectMapper;
6	import org.springframework.stereotype.Service;
7	
8	import java.time.LocalDateTime;
9	
10	@Service
11	public class IdempotencyService {
12	
13	    private static final int TOKEN_VALIDITY_MINUTES = 10;
14	
15	    private final IdempotencyTokenMapper tokenMapper;
16	    private final ObjectMapper objectMapper;
17	
18	    public IdempotencyService(IdempotencyTokenMapper tokenMapper, ObjectMapper objectMapper) {
19	        this.tokenMapper = tokenMapper;
20	        this.objectMapper = objectMapper;
21	    }
22	
23	    public static class IdempotencyResult {
24	        public final boolean isDuplicate;
25	        public final Integer cachedStatus;
26	        public final String cachedBody;
27	
28	        public IdempotencyResult(boolean isDuplicate, Integer cachedStatus, String cachedBody) {
29	            this.isDuplicate = isDuplicate;
30	            this.cachedStatus = cachedStatus;
31	            this.cachedBody = cachedBody;
32	        }
33	    }
34	
35	    /**
36	     * Checks an idempotency token scoped to a specific order+action combination.
37	     * The compound key prevents caching collisions across different actions on the same order.
38	     */
39	    public IdempotencyResult checkToken(String token, String action, Long orderId) {
40	        if (token == null || token.isBlank()) return new IdempotencyResult(false, null, null);
41	
42	        // Build a compound key: token + action + orderId to prevent cross-action collisions
43	        String scopedKey = token + "::" + action + "::" + (orderId != null ? orderId : "new");
44	
45	        IdempotencyToken existing = tokenMapper.findByToken(scopedKey);
46	        if (existing != null) {
47	            if (existing.isExpired()) {
48	                return new IdempotencyResult(false, null, null);
49	            }
50	            if (existing.getResponseStatus() != null) {
51	                return new IdempotencyResult(true, existing.getResponseStatus(), existing.getResponseBody());
52	            }
53	            return new IdempotencyResult(true, 409, "{\"error\":\"Request is already being processed\"}");
54	        }
55	
56	        IdempotencyToken newToken = new IdempotencyToken();
57	        newToken.setToken(scopedKey);
58	        newToken.setAction(action);
59	        newToken.setOrderId(orderId);
60	        newToken.setExpiresAt(LocalDateTime.now().plusMinutes(TOKEN_VALIDITY_MINUTES));
61	        try {
62	            tokenMapper.insert(newToken);
63	        } catch (Exception e) {
64	            return new IdempotencyResult(true, 409, "{\"error\":\"Duplicate request\"}");
65	        }
66	
67	        return new IdempotencyResult(false, null, null);
68	    }
69	
70	    /** @deprecated Use checkToken(token, action, orderId) for proper scoping */
71	    @Deprecated
72	    public IdempotencyResult checkToken(String token, String action) {
73	        return checkToken(token, action, null);
74	    }
75	
76	    public void recordResponse(String token, String action, Long orderId, int status, String body) {
77	        if (token == null || token.isBlank()) return;
78	        String scopedKey = token + "::" + action + "::" + (orderId != null ? orderId : "new");
79	        try {
80	            tokenMapper.updateResponse(scopedKey, status, body);
81	        } catch (Exception e) {
82	            // Non-critical
83	        }
84	    }
85	
86	    /** @deprecated Use recordResponse(token, action, orderId, status, body) for proper scoping */
87	    @Deprecated
88	    public void recordResponse(String token, Long orderId, int status, String body) {
89	        // Fallback — cannot reconstruct the scoped key without action
90	        if (token == null || token.isBlank()) return;
91	        try {
92	            tokenMapper.updateResponse(token, status, body);
93	        } catch (Exception e) {
94	            // Non-critical
95	        }
96	    }
97	
98	    public void cleanupExpired() {
99	        tokenMapper.deleteExpired(LocalDateTime.now());
100	    }
101	}
