163	    @FunctionalInterface
164	    private interface OrderAction {
165	        Order execute(Order order, User user);
166	    }
167	
168	    private ResponseEntity<?> executeAction(String idempotencyKey, String action,
169	                                            Long orderId, HttpSession session,
170	                                            OrderAction orderAction) {
171	        IdempotencyResult idem = idempotencyService.checkToken(idempotencyKey, action, orderId);
172	        if (idem.isDuplicate) {
173	            return ResponseEntity.status(idem.cachedStatus).body(idem.cachedBody);
174	        }
175	
176	        User user = SessionUtil.getCurrentUser(session);
177	        try {
178	            Order order = orderService.getById(orderId);
179	            if (order == null) {
180	                idempotencyService.recordResponse(idempotencyKey, action, null, 404, "Order not found");
181	                return ResponseEntity.notFound().build();
182	            }
183	            if (!orderService.canUserAccess(order, user)) {
184	                idempotencyService.recordResponse(idempotencyKey, action, orderId, 403, "Access denied");
185	                return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
186	            }
187	
188	            Order result = orderAction.execute(order, user);
189	            String body = objectMapper.writeValueAsString(result);
190	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 200, body);
191	            return ResponseEntity.ok(result);
192	        } catch (IllegalArgumentException | IllegalStateException e) {
193	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 400, e.getMessage());
194	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
195	        } catch (SecurityException e) {
196	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 403, e.getMessage());
197	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
198	        } catch (Exception e) {
199	            idempotencyService.recordResponse(idempotencyKey, action, orderId, 500, e.getMessage());
200	            return ResponseEntity.internalServerError().body(Map.of("error", "Operation failed"));
201	        }
202	    }
203	}
