240	    @Transactional
241	    public Order refund(Long orderId, BigDecimal amount, String reason, User actor) {
242	        Order order = requireOrder(orderId);
243	        enforceAccess(order, actor, "ADMINISTRATOR");
244	
245	        OrderStatus current = OrderStatus.valueOf(order.getStatus());
246	        if (!current.isRefundable() && current != OrderStatus.CANCELLED) {
247	            throw new IllegalStateException("Order is not refundable in status " + current);
248	        }
249	
250	        if (current != OrderStatus.CANCELLED) {
251	            transition(order, OrderStatus.REFUNDED, actor.getId(),
252	                    "Refund of " + amount + ": " + reason);
253	        }
254	        // APPROVAL notification: inform customer of refund approval
255	        notificationService.queueApprovalNotification(order.getCustomerId(),
256	                order.getOrderNumber(), "Refund of $" + amount + " approved");
257	        order.setRefundAmount(amount);
258	        order.setStatus(order.getStatus().equals(OrderStatus.CANCELLED.name()) ?
259	                OrderStatus.CANCELLED.name() : OrderStatus.REFUNDED.name());
260	        orderMapper.update(order);
261	
262	        // Release slot if not already released
263	        if (current != OrderStatus.CANCELLED) {
264	            timeSlotService.releaseSlot(order.getTimeSlotId());
265	        }
266	
267	        // Deduct points — lookup the payment rule value for consistent reversal
268	        com.booking.domain.PointsRule payRule = pointsRuleMapper.findByTrigger("ORDER_PAID");
269	        int deductAmt = (payRule != null) ? payRule.getPoints() : 10;
270	        pointsService.deductPoints(order.getCustomerId(), deductAmt,
271	                "REFUND_DEDUCTION", "ORDER", order.getId(),
272	                "Points reversed for refunded order " + order.getOrderNumber());
273	
274	        notificationService.queueOrderNotification(order, "ORDER_REFUNDED",
275	                "Refund of $" + amount + " processed for order " + order.getOrderNumber());
276	        return orderMapper.findById(orderId);
277	    }
278	
279	    @Transactional
280	    public Order reschedule(Long orderId, Long newTimeSlotId, User actor) {
281	        Order order = requireOrder(orderId);
282	        enforceAccess(order, actor, "CUSTOMER", "ADMINISTRATOR");
283	
284	        OrderStatus current = OrderStatus.valueOf(order.getStatus());
285	        if (!current.canReschedule()) {
286	            throw new IllegalStateException("Cannot reschedule from status " + current);
287	        }
288	
289	        Long oldSlotId = order.getTimeSlotId();
290	
291	        // Verify new slot belongs to the same listing as the order
292	        com.booking.domain.TimeSlot newSlotCheck = timeSlotService.getById(newTimeSlotId);
293	        if (newSlotCheck == null) {
294	            throw new IllegalArgumentException("Time slot not found");
295	        }
296	        if (!newSlotCheck.getListingId().equals(order.getListingId())) {
297	            throw new IllegalArgumentException("Cannot reschedule to a slot from a different listing");
298	        }
299	
300	        // Reserve new slot first
301	        try {
302	            timeSlotService.reserveSlot(newTimeSlotId);
303	        } catch (IllegalStateException e) {
304	            throw new IllegalStateException("New time slot unavailable: " + e.getMessage());
305	        }
306	
307	        // Release old slot
308	        try {
309	            timeSlotService.releaseSlot(oldSlotId);
310	        } catch (Exception e) {
311	            // Compensating rollback: release the newly reserved slot
312	            timeSlotService.releaseSlot(newTimeSlotId);
313	            throw new RuntimeException("Reschedule failed during old slot release", e);
314	        }
315	
316	        order.setTimeSlotId(newTimeSlotId);
317	        orderMapper.update(order);
318	
319	        recordAction(orderId, "RESCHEDULE", current.name(), current.name(),
320	                actor.getId(), "Rescheduled from slot " + oldSlotId + " to " + newTimeSlotId);
321	
322	        notificationService.queueOrderNotification(order, "ORDER_RESCHEDULED",
323	                "Order " + order.getOrderNumber() + " has been rescheduled");
324	        return orderMapper.findById(orderId);
325	    }
326	
327	    @Transactional
328	    public void autoCloseUnpaidOrders() {
329	        List<Order> expired = orderMapper.findUnpaidExpired(LocalDateTime.now());
330	        for (Order order : expired) {
331	            log.info("Auto-closing unpaid order {}", order.getOrderNumber());
332	            transition(order, OrderStatus.CANCELLED, 1L, "Auto-cancelled: payment deadline expired");
333	            order.setCancelReason("Payment deadline expired");
334	            order.setStatus(OrderStatus.CANCELLED.name());
335	            orderMapper.update(order);
336	            timeSlotService.releaseSlot(order.getTimeSlotId());
337	            notificationService.queueOrderNotification(order, "ORDER_AUTO_CANCELLED",
338	                    "Order " + order.getOrderNumber() + " cancelled due to payment timeout");
339	        }
340	    }
341	
342	    /**
343	     * Sends overdue warnings for orders approaching payment deadline (within 10 minutes).
344	     */
345	    public void sendOverdueWarnings() {
346	        LocalDateTime warningThreshold = LocalDateTime.now().plusMinutes(10);
347	        List<Order> approaching = orderMapper.findUnpaidExpired(warningThreshold);
348	        for (Order order : approaching) {
349	            if ("CREATED".equals(order.getStatus())) {
350	                notificationService.queueOverdueNotification(
351	                        order.getCustomerId(), order.getOrderNumber());
352	            }
353	        }
354	    }
355	
356	    private Order requireOrder(Long orderId) {
357	        Order order = orderMapper.findById(orderId);
358	        if (order == null) throw new IllegalArgumentException("Order not found");
359	        return order;
360	    }
361	
362	    private void enforceAccess(Order order, User actor, String... allowedRoles) {
363	        if ("ADMINISTRATOR".equals(actor.getRoleName())) return;
364	        for (String role : allowedRoles) {
365	            if (role.equals(actor.getRoleName())) {
366	                if ("CUSTOMER".equals(role) && order.getCustomerId().equals(actor.getId())) return;
367	                if ("PHOTOGRAPHER".equals(role) && order.getPhotographerId().equals(actor.getId())) return;
368	            }
369	        }
370	        throw new SecurityException("Access denied to this order");
371	    }
372	
373	    private void transition(Order order, OrderStatus target, Long actorId, String detail) {
374	        OrderStatus current = OrderStatus.valueOf(order.getStatus());
375	        if (!current.canTransitionTo(target)) {
376	            throw new IllegalStateException("Invalid transition: " + current + " -> " + target);
377	        }
378	        orderMapper.updateStatus(order.getId(), target.name());
379	        recordAction(order.getId(), target.name(), current.name(), target.name(), actorId, detail);
380	    }
381	
382	    private void awardByRule(String triggerEvent, Order order) {
383	        pointsService.awardByTrigger(triggerEvent, order.getCustomerId(),
384	                "ORDER", order.getId(), "for order " + order.getOrderNumber());
385	    }
386	
387	    private void recordAction(Long orderId, String action, String from, String to,
388	                              Long performedBy, String detail) {
389	        OrderAction oa = new OrderAction();
390	        oa.setOrderId(orderId);
391	        oa.setAction(action);
392	        oa.setFromStatus(from);
393	        oa.setToStatus(to);
394	        oa.setPerformedBy(performedBy);
395	        oa.setDetail(detail);
396	        orderActionMapper.insert(oa);
397	    }
398	}
