31	            .andExpect(jsonPath("$.totalPrice").isNumber());
32	    }
33	
34	    @Test @Order(2)
35	    void idempotencyReturnsCachedResponse() throws Exception {
36	        MockHttpSession cust = loginAs("cust1");
37	        // First call
38	        mvc.perform(post("/api/orders").session(cust)
39	                .contentType(MediaType.APPLICATION_JSON)
