44	        mvc.perform(post("/api/orders").session(cust)
45	                .contentType(MediaType.APPLICATION_JSON)
46	                .header("Idempotency-Key", "api-test-idem-dup")
47	                .content(json(Map.of("listingId", 1, "timeSlotId", 2))))
48	            .andExpect(status().isOk());
