141	    // ---- True parallel concurrency test against the DB ----
142	
143	    @Test @Order(7) void trueParallelSlotOversellPrevention() throws Exception {
144	        MockHttpSession photo = loginAs("photo1");
145	
146	        // Create a capacity-1 slot
147	        MvcResult slotR = mvc.perform(post("/api/timeslots").session(photo)
148	                .contentType(MediaType.APPLICATION_JSON)
149	                .content(json(Map.of("listingId", 1, "slotDate", "2027-04-01",
150	                        "startTime", "09:00", "endTime", "10:00", "capacity", 1))))
151	            .andExpect(status().isOk()).andReturn();
152	        int slotId = ((Number) parseMap(slotR).get("id")).intValue();
153	
154	        // Launch 5 threads all trying to book the same slot simultaneously
155	        int threadCount = 5;
156	        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
157	        CountDownLatch startGate = new CountDownLatch(1);
158	        List<Future<Integer>> futures = new ArrayList<>();
159	
160	        for (int i = 0; i < threadCount; i++) {
161	            final int idx = i;
162	            futures.add(executor.submit(() -> {
163	                startGate.await(); // Wait for all threads to be ready
164	                MockHttpSession s = loginAs("cust1");
165	                MvcResult r = mvc.perform(post("/api/orders").session(s)
166	                        .contentType(MediaType.APPLICATION_JSON)
167	                        .header("Idempotency-Key", "race-parallel-" + idx)
168	                        .content(json(Map.of("listingId", 1, "timeSlotId", slotId))))
169	                    .andReturn();
170	                return r.getResponse().getStatus();
171	            }));
172	        }
173	
174	        startGate.countDown(); // Release all threads simultaneously
175	
176	        int successes = 0;
177	        int failures = 0;
178	        for (Future<Integer> f : futures) {
179	            int status = f.get(10, TimeUnit.SECONDS);
180	            if (status == 200) successes++;
181	            else failures++;
182	        }
183	        executor.shutdown();
184	
185	        // Exactly 1 should succeed, the rest should fail
186	        org.junit.jupiter.api.Assertions.assertEquals(1, successes,
187	                "Exactly 1 booking should succeed under parallel contention, got " + successes);
188	        org.junit.jupiter.api.Assertions.assertEquals(threadCount - 1, failures,
189	                "All other threads should fail with oversell prevention");
190	    }
