18	
19	@SpringBootTest
20	@AutoConfigureMockMvc
21	@ActiveProfiles("test")
22	abstract class BaseApiIT {
23	
24	    protected static final String TEST_ORIGIN = "http://localhost";
25	
26	    @Autowired protected MockMvc mvc;
27	    @Autowired protected ObjectMapper om;
28	
29	    protected MockHttpSession loginAs(String username) throws Exception {
30	        MockHttpSession session = new MockHttpSession();
31	        mvc.perform(post("/api/auth/login")
32	                .session(session)
33	                .contentType(MediaType.APPLICATION_JSON)
34	                .content(om.writeValueAsString(Map.of("username", username, "password", "password123"))))
35	            .andExpect(status().isOk());
36	        return session;
37	    }
38	
39	    protected static MockHttpServletRequestBuilder withOrigin(MockHttpServletRequestBuilder builder) {
40	        return builder.header("Origin", TEST_ORIGIN);
41	    }
42	
43	    protected String json(Object obj) throws Exception {
44	        return om.writeValueAsString(obj);
45	    }
46	
47	    @SuppressWarnings("unchecked")
48	    protected Map<String, Object> parseMap(MvcResult r) throws Exception {
49	        return om.readValue(r.getResponse().getContentAsString(), Map.class);
50	    }
51	}
