149	
150	    @Test @Order(7) void trueParallelSlotOversellPrevention() throws Exception {
151	        MockHttpSession photo = loginAs("photo1");
152	
153	        // Create a capacity-1 slot
154	        MvcResult slotR = mvc.perform(post("/api/timeslots").session(photo)
155	                .header("Origin", TEST_ORIGIN)
156	                .contentType(MediaType.APPLICATION_JSON)
157	                .content(json(Map.of("listingId", 1, "slotDate", "2027-04-01",
158	                        "startTime", "09:00", "endTime", "10:00", "capacity", 1))))
159	            .andExpect(status().isOk()).andReturn();
160	        int slotId = ((Number) parseMap(slotR).get("id")).intValue();
161	
162	        // Launch 5 threads all trying to book the same slot simultaneously
163	        int threadCount = 5;
164	        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
165	        CountDownLatch startGate = new CountDownLatch(1);
166	        List<Future<Integer>> futures = new ArrayList<>();
167	
168	        for (int i = 0; i < threadCount; i++) {
169	            final int idx = i;
170	            futures.add(executor.submit(() -> {
171	                startGate.await(); // Wait for all threads to be ready
172	                MockHttpSession s = loginAs("cust1");
173	                MvcResult r = mvc.perform(post("/api/orders").session(s)
174	                        .header("Origin", TEST_ORIGIN)
175	                        .contentType(MediaType.APPLICATION_JSON)
176	                        .header("Idempotency-Key", "race-parallel-" + idx)
177	                        .content(json(Map.of("listingId", 1, "timeSlotId", slotId))))
178	                    .andReturn();
179	                return r.getResponse().getStatus();
180	            }));
181	        }
182	
183	        startGate.countDown(); // Release all threads simultaneously
184	
185	        int successes = 0;
186	        int failures = 0;
187	        for (Future<Integer> f : futures) {
188	            int status = f.get(10, TimeUnit.SECONDS);
189	            if (status == 200) successes++;
190	            else failures++;
191	        }
192	        executor.shutdown();
193	
194	        // Exactly 1 should succeed, the rest should fail
195	        org.junit.jupiter.api.Assertions.assertEquals(1, successes,
196	                "Exactly 1 booking should succeed under parallel contention, got " + successes);
197	        org.junit.jupiter.api.Assertions.assertEquals(threadCount - 1, failures,
198	                "All other threads should fail with oversell prevention");
199	    }
