131	    @Test
132	    void concurrentPointsAwardsProduceCorrectBalance() throws Exception {
133	        MockHttpSession admin = loginAs("admin");
134	
135	        // Get initial balance for user 5
136	        MvcResult balR = mvc.perform(get("/api/points/balance").session(loginAs("cust2")))
137	            .andExpect(status().isOk()).andReturn();
138	        int initialBalance = ((Number) parseMap(balR).get("balance")).intValue();
139	
140	        int threadCount = 5;
141	        int pointsPerAward = 10;
142	        CountDownLatch ready = new CountDownLatch(threadCount);
143	        CountDownLatch go = new CountDownLatch(1);
144	        AtomicInteger successCount = new AtomicInteger(0);
145	        ExecutorService executor = Executors.newFixedThreadPool(threadCount);
146	
147	        for (int i = 0; i < threadCount; i++) {
148	            final int idx = i;
149	            executor.submit(() -> {
150	                try {
151	                    MockHttpSession adminSession = loginAs("admin");
152	                    ready.countDown();
153	                    go.await();
154	                    mvc.perform(post("/api/points/adjust").session(adminSession)
155	                            .header("Origin", TEST_ORIGIN)
156	                            .contentType(MediaType.APPLICATION_JSON)
157	                            .content(json(Map.of("userId", 5, "points", pointsPerAward,
158	                                    "reason", "Concurrent test " + idx))))
159	                        .andExpect(status().isOk());
160	                    successCount.incrementAndGet();
161	                } catch (Exception e) {
162	                    // Test will fail on balance check
163	                }
164	            });
165	        }
166	
167	        ready.await();
168	        go.countDown();
169	        executor.shutdown();
170	        while (!executor.isTerminated()) {
171	            Thread.sleep(50);
172	        }
173	
174	        assertEquals(threadCount, successCount.get(), "All concurrent awards should succeed");
175	
176	        // Verify final balance is exactly initialBalance + (threadCount * pointsPerAward)
177	        MvcResult finalR = mvc.perform(get("/api/points/balance").session(loginAs("cust2")))
178	            .andExpect(status().isOk()).andReturn();
179	        int finalBalance = ((Number) parseMap(finalR).get("balance")).intValue();
180	        assertEquals(initialBalance + threadCount * pointsPerAward, finalBalance,
181	            "Balance should reflect all concurrent awards atomically");
182	    }
