import re
import os

# List all test files
test_files = [f for f in os.listdir('.') if f.endswith('ApiIT.java')]

issues = []

for filename in test_files:
    with open(filename, 'r') as f:
        lines = f.readlines()

    # Find all lines with POST/PUT/PATCH/DELETE operations
    for i, line in enumerate(lines):
        if re.search(r'mvc\.perform\((post|put|patch|delete)\(', line):
            # Skip /api/auth paths
            if '/api/auth/' in line:
                continue

            # Look ahead up to 10 lines to see if Origin header is added
            found_origin = False
            found_auth_endpoint = False
            is_csrf_test = False

            # Check the context for the test name
            for j in range(max(0, i-10), i):
                if 'csrfReject' in lines[j] or 'csrfAllow' in lines[j] or 'csrf' in lines[j].lower():
                    is_csrf_test = True

            # Look ahead for Origin header in next 8 lines
            for j in range(i, min(i+8, len(lines))):
                if 'header("Origin"' in lines[j]:
                    found_origin = True
                    break
                if '/api/auth/' in lines[j]:
                    found_auth_endpoint = True
                    break

            # Report issues (excluding intentional CSRF tests)
            if not found_origin and not found_auth_endpoint and not is_csrf_test:
                # Extract the path from the line
                path_match = re.search(r'\((post|put|patch|delete)\("([^"]+)"', line)
                if path_match:
                    method = path_match.group(1).upper()
                    path = path_match.group(2)
                    issues.append((filename, i+1, method, path))

# Print results
if issues:
    print(f"Found {len(issues)} potential issues:\n")
    for filename, linenum, method, path in issues:
        print(f"{filename}:{linenum} - {method} {path} (missing Origin header)")
else:
    print("No issues found! All POST/PUT/PATCH/DELETE requests (except /api/auth and CSRF tests) have Origin headers.")
EOF
"}

