import re
import os

test_files = [f for f in os.listdir('.') if f.endswith('ApiIT.java')]

missing_origin = []
csrf_tests = []

for filename in test_files:
    with open(filename, 'r') as f:
        content = f.read()
        lines = content.split('\n')

    # Find all lines with POST/PUT/PATCH/DELETE operations (not on /api/auth)
    for i, line in enumerate(lines):
        match = re.search(r'mvc\.perform\((post|put|patch|delete)\("([^"]+)"', line)
        if match:
            method = match.group(1).upper()
            path = match.group(2)

            # Skip /api/auth paths
            if '/api/auth/' in path:
                continue

            # Look ahead to find if Origin header is present
            found_origin = False
            is_csrf_test = False

            # Check test name context (look back)
            for j in range(max(0, i-15), i):
                if 'csrf' in lines[j].lower():
                    is_csrf_test = True
                    break

            # Look ahead in the call chain
            for j in range(i, min(i+15, len(lines))):
                if 'header("Origin"' in lines[j]:
                    found_origin = True
                    break
                # Stop at the end of the mvc.perform call
                if '.andExpect(' in lines[j]:
                    break

