1	package com.booking.util;
2	
3	import com.booking.domain.User;
4	import jakarta.servlet.http.HttpSession;
5	
6	public final class RoleGuard {
7	
8	    private RoleGuard() {}
9	
10	    public static User requireLogin(HttpSession session) {
11	        User user = SessionUtil.getCurrentUser(session);
12	        if (user == null) throw new SecurityException("Authentication required");
13	        return user;
14	    }
15	
16	    public static User requireAdmin(HttpSession session) {
17	        User user = requireLogin(session);
18	        if (!"ADMINISTRATOR".equals(user.getRoleName())) {
19	            throw new SecurityException("Administrator access required");
20	        }
21	        return user;
22	    }
23	
24	    public static User requireRole(HttpSession session, String... roles) {
25	        User user = requireLogin(session);
26	        for (String role : roles) {
27	            if (role.equals(user.getRoleName())) return user;
28	        }
29	        throw new SecurityException("Insufficient role: required one of " + String.join(", ", roles));
30	    }
31	
32	    public static void requireOwnerOrAdmin(HttpSession session, Long ownerId) {
33	        User user = requireLogin(session);
34	        if (!"ADMINISTRATOR".equals(user.getRoleName()) && !user.getId().equals(ownerId)) {
35	            throw new SecurityException("Access denied");
36	        }
37	    }
38	}
